// Access the input from the previous node
const raw = $input.first().json.text; 

// Extract the JSON array from the text using regex
const match = raw.match(/\[[\s\S]*\]/);
if (!match) throw new Error("Pas de JSON trouvé");

const articles = JSON.parse(match[0]);

// Return the formatted items for the Discord/HTTP node
return articles.map(article => ({
  json: {
    embeds: [{
      // Added backticks here to make this a valid Template Literal
      title: `[${article.importance.toUpperCase()}] ${article.titre}`,
      url: article.lien,
      description: article.resume,
      color: article.importance === 'haute' ? 15158332 : 
             article.importance === 'moyenne' ? 16776960 : 3447003,
      footer: { text: article.date }
    }]
  }
}));

// Access the search results array from the Search node
const results = $input.first().json.results;

if (!results || !Array.isArray(results)) {
  throw new Error("No search results found to process.");
}

// Map the search results to the Discord embed format
return results.map(item => ({
  json: {
    embeds: [{
      // Added backticks and updated keys to match Tavily output
      title: `[SEARCH] ${item.title}`,
      url: item.url,
      description: item.content.substring(0, 1000), // Limit length for Discord
      color: 3447003, // Default blue color
      footer: { text: `Source: Tavily Search` }
    }]
  }
}));
